// Transformation systématique
function transformPrompt(vaguePrompt) {
  return {
    avant: vaguePrompt,
    analyse: identifyWeaknesses(vaguePrompt),
    transformation: {
      role: addExpertRole(),
      contexte: addSpecificContext(),
      tache: clarifyObjective(),
      format: defineStructure()
    },
    apres: buildFinalPrompt()
  };
}

